var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"난 복잡한 얘기는 별로 관심없어.","JPN":"こっちは難しい話には興味ねえんだ。","ENG":"I'm not interested in complicated things.","TWN":"我對複雜的事情沒什麼興趣。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"역시 싸움이 최고지! 한 방에 한 놈씩 땅바닥에 꽂아 버릴 때마다 기분 째지거든!","JPN":"アタシはとにかく喧嘩がしてえ！喧嘩はいいぜ。一人一発ずつぶん殴って地面に叩きつけてやりゃ、スカッとできるしな！","ENG":"All I know is fighting. It feels awesome when I knock my enemies down, one by one.","TWN":"果然打架才是王道！一拳把一個傢伙打倒在地，這感覺真是爽呆了！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"하아...... 근데 요샌 내 소문이 이 근처까지 쫙 퍼진 것 같단 말이야......","JPN":"ふぅ……だというのに、近頃はこの辺りにまでアタシの噂が広まっちまったみたいでな……","ENG":"*Sigh* But it seems that the word has gotten out about me.","TWN":"唉……但是最近，關於我的傳聞好像傳到這裡來了……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"어떻게 된 게 하루 종일 싸돌아다녀도 시비 거는 놈이 한 놈도 없을 수 있어?","JPN":"一日中歩き回ったってのに、喧嘩を吹っかけてくる奴が一人もいやしねえ。あり得ないだろ？","ENG":"No one seems to want to pick a fight with me, no matter how long I roam the streets.","TWN":"不然怎麼可能我溜達了一天，也沒人上來挑釁？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"아, 진짜! 생각하니까 또 주먹 근질거려서 미치겠네!","JPN":"ああ、もう！思い出したら、また拳がうずいてきたじゃねえか！","ENG":"Darn it! Thinking about that makes my fists itch again!","TWN":"啊，真是的！一想到這裡，我的拳頭就癢到快要瘋了！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"그러니까 종신...... 그 종신 뭔가인가 하여튼 그거, 꼭 내 입으로 말해 줘야 돼?","JPN":"つまり、その……あれだよあれ、終身なんちゃらってヤツ。アタシの口から言わなきゃなんないのか？","ENG":"So that lifetime whatever that you're talking about... Do I really have to say it in words?","TWN":"所以，終身……那個終身什麼來著，還要我親口告訴你嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"알잖아. 딴 녀석들이 하란 대로 하는 건 내 방식에 안 맞는다고.","JPN":"知ってんだろ？他の奴らのやり方はアタシの性に合わねえんだよ。","ENG":"You know how I feel about people ordering me around.","TWN":"你知道的嘛。別人說什麼就做什麼，這可不是我的風格。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"근데 그걸 알면서도 이런 종이를 들이밀어? 혹시 나랑 한 판 붙어 보잔 거야, 응?","JPN":"知ってるくせして、そんな紙切れをアタシに突きつけてきやがって。ひょっとして喧嘩売ってんのか？あぁ？","ENG":"And you still had the nerve to shove this stupid paper in my face? Are you provoking me into a fight? Huh? Is that what you're doing?","TWN":"你都知道這種事了，還把這張紙推給我？你是想和我打一架嗎，啊？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"......킥킥, 눈도 깜짝 안 하네. 주먹질 한 번 안 해 본 것처럼 생겨선 배짱만 좋아 가지곤.","JPN":"……ククッ、眉一つ動かさねえと来た。大人しそうなナリして、肝っ玉の太い野郎だぜ。","ENG":"*Giggle* You didn't even blink. You have guts for someone who looks so meek.","TWN":"……嘻嘻，眼睛眨都不眨一下。看起來弱不禁風的，膽子倒是不小嘛。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"뭐, 부탁하는 게 영 심심하긴 한데~","JPN":"まあ、どうせならもっと闘志に火がつくような頼み方をしてほしかったな。","ENG":"Well, I don't like the way you're asking me...","TWN":"不過，這請求是很無聊沒錯啦～"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"주인님은 내가 싸우는 걸 마음에 들어하시거든. 그때 뭐랬더라......","JPN":"主様はアタシが喧嘩すると喜んでくれるのさ。えーと、何つってたかな……","ENG":"But Mistress likes it when I fight. What was the word that she used the other day?","TWN":"但主人非常喜歡我打架。那時候說什麼來著……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"아, 그래! 꼴사납다더라고!","JPN":"あっ、そうそう！とんだ暴れ馬だって言ってたな！","ENG":"Oh, yeah! Unsightly!","TWN":" 啊，對了！真讓人討厭！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"뭔 뜻인지 몰라도 사납다고 하니까 좋은 말이겠지? 안 그래?","JPN":"どういう意味だか知らねえけど、誉め言葉なんだよな？だって暴れると気持ちイイしな！","ENG":"I don't know what it means exactly, but I bet it's a compliment, because it has the word sight in it. So basically,","TWN":"雖然不知道這是什麼意思，但既然說我討厭，就是在誇我，對吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"어쨌든 그럼 내가 자꾸 싸우고 다녀야 주인님도 좋아하시지 않겠냐, 이 말이야.","JPN":"まあ、そんなわけで、アタシはもっともっと暴れまくって、主様に喜んでもらいてえ。","ENG":"I think the more I go around, the happier Mistress will be.","TWN":"反正就是說，只要我一直打架，主人就會高興吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"근데 사장님은 박 터지게 싸울 놈들만 찾아다니잖아?","JPN":"そこでだ。あんたは次から次に喧嘩相手を見つけてくれるだろ？","ENG":"And all you do, Boss, is to look around for fights.","TWN":"而且老闆不是只找那些打架很火爆的傢伙嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"사장님은 찾고 패는 건 내가 하는 거야! 이거 진짜 끝내 주는 콤보 아냐?","JPN":"あんたが相手を見つけて、それをアタシがぶん殴る！どうよ、見事なワンツーコンボだろ？","ENG":"You do the looking, and I do the fighting! How awesome is that?","TWN":"老闆找人，我來幹架！這根本是最佳拍檔吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"오빠도 내가 여기 있는 게 주인님을 돕는 거라고 그랬고!","JPN":"兄さんだって、アタシはここにいた方が主様を助けることになるって言ってたからな！","ENG":"And Doma also said I'm helping Mistress by staying here with you.","TWN":"哥哥也說過，我在這裡是在幫助主人！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"으하하하하!","JPN":"アーッハハハハッ！","ENG":"Mwa hah hah!","TWN":"哇哈哈哈哈！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"하하...... 하.......","JPN":"ハハ……ハ……","ENG":"Hah hah... Hah...","TWN":"哈哈……哈……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"......아, 씨. 이건 말하지 말랬는데. 방금 얘긴 못 들은 거다?","JPN":"……クッ、まずったぜ。今のは内緒だって言われてるんだった。なぁ、聞かなかったことにしてくれるか？","ENG":"Oh, crap. I just remembered. I wasn't supposed to tell you that. Just pretend you never heard that, okay?","TWN":"……啊，糟糕。他要我別說出去的。剛才那句話你就當沒聽到吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};